   276	ImprovedTube.setPrefCookieValueByName = function (name, value) {
   277		let originalPref = this.getCookieValueByName('PREF');
   278		let prefs = this.getParams(originalPref);
   279		let newPrefs = '';
   280		let ampersant = '';
   281	
   282		if (name == 'f6' && prefs[name] & 1) {
   283			// f6 holds other settings, possible values 80000 80001 400 401 1 none
   284			// make sure we remember 1 bit
   285			prefs[name] = value | 1;
   286		} else {
   287			prefs[name] = value;
   288		}
