/**
 * Tests for theme switching - specifically the bug:
 * "After clicking on YouTube's Dark theme and then YouTube's Light theme,
 *  the background doesn't change to Light"
 *
 * This test focuses on the setPrefCookieValueByName function which modifies
 * the PREF cookie's f6 parameter.
 */
'use strict';

// We need jsdom environment for document, DOM APIs
/**
 * @jest-environment jsdom
 */

// Recreate the necessary functions in isolation to test the logic
// without needing the full browser extension environment

function getParams(query) {
    var params = query.split('&'),
        result = {};

    for (var i = 0, l = params.length; i < l; i++) {
        params[i] = params[i].split('=');

        result[params[i][0]] = params[i][1];
    }

    return result;
}

function getCookieValueByName(name, cookieJar) {
    var match = cookieJar.match(new RegExp('([; ]' + name + '|^' + name + ')([^\\s;]*)', 'g'));

    if (match) {
        var cookie = match[0];

        return cookie.replace(name + '=', '').replace(' ', '');
    } else return '';
}

function setPrefCookieValueByName(name, value, cookieJar) {
    let originalPref = getCookieValueByName('PREF', cookieJar);
    let prefs = getParams(originalPref);
    let newPrefs = '';
    let ampersant = '';

    if (name == 'f6' && prefs[name] & 1) {
        // f6 holds other settings, possible values 80000 80001 400 401 1 none
        // make sure we remember 1 bit
        prefs[name] = value | 1;
    } else {
        prefs[name] = value;
    }

    for (let pref in prefs) {
        if (prefs[pref]) {
            newPrefs += ampersant + pref + '=' + prefs[pref];
            ampersant = '&';
        }
    }
    return { originalPref, newPrefs, changed: originalPref != newPrefs, f6Value: prefs['f6'] };
}

describe('Theme switching - setPrefCookieValueByName', () => {

    test('Setting dark theme (f6=400) when PREF cookie has no f6', () => {
        const cookieJar = 'PREF=hl=en&tz=America.Los_Angeles';
        const result = setPrefCookieValueByName('f6', 400, cookieJar);

        expect(result.originalPref).toBe('hl=en&tz=America.Los_Angeles');
        expect(result.newPrefs).toBe('hl=en&tz=America.Los_Angeles&f6=400');
        expect(result.changed).toBe(true);
        expect(result.f6Value).toBe(400);
    });

    test('Setting light theme (f6=null) when PREF cookie has f6=400 (simple dark→light)', () => {
        const cookieJar = 'PREF=f6=400&hl=en';
        const result = setPrefCookieValueByName('f6', null, cookieJar);

        expect(result.originalPref).toBe('f6=400&hl=en');
        expect(result.newPrefs).toBe('hl=en');
        expect(result.changed).toBe(true);
        expect(result.f6Value).toBe(null);
    });

    test('Setting dark theme (f6=400) when PREF cookie has f6=80001 (1-bit set)', () => {
        const cookieJar = 'PREF=f6=80001&hl=en';
        const result = setPrefCookieValueByName('f6', 400, cookieJar);

        // 80001 & 1 = 1, so value is preserved: 400 | 1 = 401
        expect(result.newPrefs).toBe('hl=en&f6=401');
        expect(result.f6Value).toBe(401);
    });

    test('BUG: Setting light theme (f6=null) when PREF cookie has f6=401 (1-bit preserved from before)', () => {
        // This is the scenario after the previous test: f6=401 is in the cookie
        // Now trying to set light theme
        const cookieJar = 'PREF=f6=401&hl=en';
        const result = setPrefCookieValueByName('f6', null, cookieJar);

        // BUG: 401 & 1 = 1, so null | 1 = 1 → f6=1 remains in cookie!
        // This means YouTube still sees a dark-mode value and doesn't switch to light.
        expect(result.f6Value).toBe(1);
        expect(result.newPrefs).toBe('hl=en&f6=1');
        // f6=1 is still present in the cookie, so dark mode persists
    });

    test('Setting light theme (f6=null) when PREF cookie has f6=80001 (directly from YT dark)', () => {
        const cookieJar = 'PREF=f6=80001&hl=en';
        const result = setPrefCookieValueByName('f6', null, cookieJar);

        // BUG: 80001 & 1 = 1, so null | 1 = 1 → f6=1 remains
        expect(result.f6Value).toBe(1);
        expect(result.newPrefs).toBe('hl=en&f6=1');
    });

    test('Setting light theme (f6=null) when PREF cookie has f6=401 (directly from YT dark with restricted mode)', () => {
        const cookieJar = 'PREF=f6=401&hl=en';
        const result = setPrefCookieValueByName('f6', null, cookieJar);

        // BUG: 401 & 1 = 1, so null | 1 = 1
        expect(result.f6Value).toBe(1);
        expect(result.newPrefs).toContain('f6=1');
    });

    test('Setting light from dark when f6=400 works correctly (no 1-bit)', () => {
        // This is the most common case: ImprovedTube sets f6=400, then user switches to light
        const cookieJar = 'PREF=f6=400&hl=en';
        const result = setPrefCookieValueByName('f6', null, cookieJar);

        // 400 & 1 = 0, so else branch: prefs.f6 = null
        // f6 is excluded from newPrefs
        expect(result.f6Value).toBe(null);
        expect(result.newPrefs).toBe('hl=en');
        expect(result.newPrefs).not.toContain('f6');
    });

    test('Dark→Light cycle when starting from native YT dark (f6=80001)', () => {
        // Step 1: User clicks "YouTube's Dark" (ImprovedTube sets f6=400)
        const afterDark = setPrefCookieValueByName('f6', 400, 'PREF=f6=80001&hl=en');
        expect(afterDark.f6Value).toBe(401); // 400 | 1 = 401

        // Step 2: User clicks "YouTube's Light"
        const cookieAfterDark = 'PREF=' + afterDark.newPrefs;
        const afterLight = setPrefCookieValueByName('f6', null, cookieAfterDark);

        // BUG: f6=1 still in cookie
        expect(afterLight.f6Value).toBe(1);
        expect(afterLight.newPrefs).toContain('f6=1');
        // The cookie should NOT contain any f6 to switch to light mode
    });
});

