/**
 * Tests for theme switching - specifically the bug:
 * "After clicking on YouTube's Dark theme and then YouTube's Light theme,
 *  the background doesn't change to Light"
 *
 * This test focuses on the setPrefCookieValueByName function which modifies
 * the PREF cookie's f6 parameter.
 */
'use strict';

// We need jsdom environment for document, DOM APIs
/**
 * @jest-environment jsdom
 */

// Recreate the necessary functions in isolation to test the logic
// without needing the full browser extension environment

function getParams(query) {
    var params = query.split('&'),
        result = {};

    for (var i = 0, l = params.length; i < l; i++) {
        params[i] = params[i].split('=');

        result[params[i][0]] = params[i][1];
    }

    return result;
}

function getCookieValueByName(name, cookieJar) {
    var match = cookieJar.match(new RegExp('([; ]' + name + '|^' + name + ')([^\\s;]*)', 'g'));

    if (match) {
        var cookie = match[0];

        return cookie.replace(name + '=', '').replace(' ', '');
    } else return '';
}

function setPrefCookieValueByName(name, value, cookieJar) {
    let originalPref = getCookieValueByName('PREF', cookieJar);
    let prefs = getParams(originalPref);
    let newPrefs = '';
    let ampersant = '';

    if (name == 'f6' && prefs[name] & 1) {
        // f6 holds other settings, possible values 80000 80001 400 401 1 none
        // make sure we remember 1 bit
        prefs[name] = value | 1;
    } else {
        prefs[name] = value;
    }

    for (let pref in prefs) {
        if (prefs[pref]) {
            newPrefs += ampersant + pref + '=' + prefs[pref];
            ampersant = '&';
        }
    }
    return { originalPref, newPrefs, changed: originalPref != newPrefs, f6Value: prefs['f6'] };
}

