        expect(afterDark.f6Value).toBe(401); // 400 | 1 = 401

        // Step 2: User clicks "YouTube's Light"
        const cookieAfterDark = 'PREF=' + afterDark.newPrefs;
        const afterLight = setPrefCookieValueByName('f6', null, cookieAfterDark);

        // FIXED: f6 should be removed from cookie, not have value 1
        expect(afterLight.f6Value).toBe(null);
        expect(afterLight.newPrefs).not.toContain('f6');
        expect(afterLight.newPrefs).toBe('hl=en');
    });

